esqlQuery.esql:
FROM logs-*
// Restrict to Azure Activity Logs
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Administrative"
// Role assignment writes indicate privilege changes — potential escalation
| WHERE azure.operation.name LIKE "*ROLEASSIGNMENTS*WRITE*" OR azure.operation.name LIKE "*ROLEASSIGNMENT*WRITE*"
// Include both success and failure — the attempt is the security signal
| STATS assignment_count = COUNT(*), roles = VALUES(azure.identity.authorization.evidence.role) BY user.name, azure.identity.authorization.evidence.principal.type, network.peer.address
| SORT assignment_count DESC
| LIMIT 20
